protocolCompatibilityTest.testCode:
describe('Protocol Compatibility', () => {
  it('should establish compatible WebSocket connection', async () => {
    // If using Socket.IO client, backend MUST use Socket.IO server
    // If using raw WebSocket client, backend MUST use raw WebSocket server
    const client = createClient(); // Socket.IO or raw WebSocket
    const server = createServer(); // MUST match client type

    await client.connect();
    const message = { type: 'test', data: 'hello' };

    const received = await new Promise(resolve => {
      server.on('message', resolve);
      client.send(message);
    });

    expect(received).toEqual(message);
  });
});

endToEndFlowTest.testCode:
describe('Terminal Communication Flow', () => {
  it('should forward user input to PTY process', async () => {
    const ptyMock = jest.fn();
    const terminal = createTerminal({ pty: ptyMock });

    // Simulate user typing
    terminal.simulateUserInput('ls\r');

    // Verify PTY receives the command
    await waitFor(() => {
      expect(ptyMock).toHaveBeenCalledWith('ls\r');
    });
  });
});

messageIntegrityTest.testCode:
describe('Message Integrity', () => {
  it('should preserve message format across transport', async () => {
    const originalMessage = {
      type: 'input',
      data: 'test\r',
      timestamp: Date.now()
    };

    const receivedMessage = await sendAndReceiveMessage(originalMessage);

    expect(receivedMessage).toEqual(originalMessage);
    expect(receivedMessage.data).toBe('test\r'); // Preserve exact formatting
  });
});
